// Parse and validate booking request data from webhook
const items = $input.all();
const output = [];

for (const item of items) {
  const body = item.json.body || item.json;

  // Extract booking fields
  const name = body.name || '';
  const email = body.email || '';
  const requestedDate = body.requestedDate || '';
  const requestedTime = body.requestedTime || '';
  const notes = body.notes || '';

  // Validate required fields
  const errors = [];

  if (!name || name.trim() === '') {
    errors.push('Name is required');
  }

  if (!email || email.trim() === '') {
    errors.push('Email is required');
  } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    errors.push('Invalid email format');
  }

  if (!requestedDate || requestedDate.trim() === '') {
    errors.push('Requested date is required');
  }

  if (!requestedTime || requestedTime.trim() === '') {
    errors.push('Requested time is required');
  }

  // Create output object
  const bookingData = {
    name: name.trim(),
    email: email.trim(),
    requestedDate: requestedDate.trim(),
    requestedTime: requestedTime.trim(),
    notes: notes.trim(),
    isValid: errors.length === 0,
    validationErrors: errors,
    rawData: body
  };

  output.push({
    json: bookingData
  });
}

return output;

// Get the calendar events from the previous node
const calendarEvents = $('Check Calendar Availability').all();

// Get the requested booking time from the parsed data
const requestedStart = $('Parse Booking Data').item.json.startTime;
const requestedEnd = $('Parse Booking Data').item.json.endTime;

// Check if there are any conflicting events
let hasConflict = false;
let conflictingEvents = [];

if (calendarEvents && calendarEvents.length > 0) {
  for (const event of calendarEvents) {
    if (event.json && event.json.start && event.json.end) {
      const eventStart = new Date(event.json.start.dateTime || event.json.start.date);
      const eventEnd = new Date(event.json.end.dateTime || event.json.end.date);
      const reqStart = new Date(requestedStart);
      const reqEnd = new Date(requestedEnd);

      // Check for overlap: events conflict if they overlap in any way
      if (reqStart < eventEnd && reqEnd > eventStart) {
        hasConflict = true;
        conflictingEvents.push({
          summary: event.json.summary,
          start: event.json.start.dateTime || event.json.start.date,
          end: event.json.end.dateTime || event.json.end.date
        });
      }
    }
  }
}

// Return the result
return [{
  json: {
    isAvailable: !hasConflict,
    hasConflict: hasConflict,
    requestedStart: requestedStart,
    requestedEnd: requestedEnd,
    conflictingEvents: conflictingEvents,
    totalEventsChecked: calendarEvents.length
  }
}];

// Get the requested booking time from the previous node
const requestedTime = new Date($('Parse Booking Data').item.json.bookingTime);

// Business hours configuration
const businessHours = {
  start: 9, // 9 AM
  end: 17   // 5 PM
};
const slotDuration = 60; // 60 minutes per slot

// Function to check if a time is within business hours
function isBusinessHours(date) {
  const hour = date.getHours();
  const day = date.getDay();
  // Monday to Friday (1-5), during business hours
  return day >= 1 && day <= 5 && hour >= businessHours.start && hour < businessHours.end;
}

// Generate alternative slots
const alternativeSlots = [];
let currentDate = new Date();
currentDate.setHours(currentDate.getHours() + 1); // Start from next hour

while (alternativeSlots.length < 3) {
  // Move to next hour
  currentDate.setHours(currentDate.getHours() + 1);
  currentDate.setMinutes(0);
  currentDate.setSeconds(0);

  // Check if within 7 days
  const daysDiff = (currentDate - new Date()) / (1000 * 60 * 60 * 24);
  if (daysDiff > 7) break;

  // Check if within business hours
  if (isBusinessHours(currentDate)) {
    alternativeSlots.push({
      startTime: new Date(currentDate).toISOString(),
      endTime: new Date(currentDate.getTime() + slotDuration * 60000).toISOString(),
      formatted: currentDate.toLocaleString('en-US', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      })
    });
  }
}

return [{
  json: {
    originalRequest: requestedTime.toISOString(),
    alternativeSlots: alternativeSlots,
    message: `Found ${alternativeSlots.length} alternative time slots`
  }
}];

